Use **`WebApplicationFactory<T>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your app in-memory and gives you an `HttpClient` — no real port, no real server.

**1. Add the NuGet package:**

```bash
dotnet add tests/MyServer.Tests package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test class:**

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (MCP is stateful)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* send initialize + initialized */ }
}
```

**3. Override services if needed** (e.g., swap a real DB for an in-memory one):

```csharp
public McpIntegrationTests(WebApplicationFactory<Program> factory)
{
    _client = factory.WithWebHostBuilder(builder =>
    {
        builder.ConfigureServices(services =>
        {
            // Replace real dependencies with fakes
            services.AddSingleton<IMyRepo, FakeRepo>();
        });
    }).CreateClient();
}
```

**Key points:**

- **`Program` must be accessible** — add `public partial class Program { }` at the bottom of your `Program.cs`, or use `[InternalsVisibleTo]`.
- **MCP is stateful** — call `initialize` → `notifications/initialized` before calling `tools/list` or `tools/call` in each test (or use a shared fixture).
- **Streamable HTTP (SSE)** — if your server uses SSE responses, read the response stream manually instead of `ReadFromJsonAsync`.
- Everything runs in-process with zero network overhead.
